const items = $input.all();

//CODIGO PARA ERROR
if(items[0].json.error || items[0].error ||
  !items[0].json.current_weather){
  return [{
    json: {
      clima_regional: {
        error: {
          nodo: "Clima multi-ciudad (Open-Meteo)",
          mensaje: "URL invalida"
        }
      }
    }
  }];
  }

const temperaturas = items.map(item => ({
  ciudad: item.json.ciudad_nombre,
  temperatura: item.json.current_weather.temperature,
  viento: item.json.current_weather.windspeed
}));

//Extraer numeros de temperatura para los calculos
const temps = temperaturas.map(t => t.temperatura);

//CALCULAR promedio
const promedio = temps.reduce((a,b) => a + b,0) / temps.length;
// Segundo calculo de promedio, esto redondea a un decimal
const promedio_2 = Math.round(promedio * 10) /10;

// TODO: calcular ciudad_mas_caliente y ciudad_mas_fria
// TODO: redondear promedio a un decimal

//Maximo
const maximo = Math.max(...temps);
//Minimo
const minimo = Math.min(...temps);

//OBTENER ciudad mas caliente
const ciudad_caliente = temperaturas.find(t => t.temperatura === maximo)?.ciudad || "Desconocido";

//OBTENER ciudad mas fria
const ciudad_fria = temperaturas.find(t => t.temperatura === minimo)?.ciudad || "Desconocido";

// MENSAJE
return[{
  json: {
    clima_regional: {
      ciudades_detalle: temperaturas,
      estadisticas: {
        promedio: promedio_2,
        maximo: maximo,
        minimo: minimo,
        ciudad_mas_caliente: ciudad_caliente,
        ciudad_mas_fria: ciudad_fria
      }
    }
  }
}];

const items = $input.all();

//Preparar variables vacias
let clima = {};
let pais = {};
let libro = {};

//VARIABLES para detectar ERRORES
let error = [];

// Almacenar los datos de clima, pais y libro
items.forEach(i => {
  //json. "Nombre de las variables que exportan los resultados, resiva los nodos anteriores"
  // RAMA 1
  if(i.json.clima_regional) {
    if(i.json.clima_regional.error){
      error.push(i.json.clima_regional.error);
      clima = {estado:"incompleto"};
    }else{
      clima = i.json.clima_regional;
    }
  }

  //RAMA 2
  if(i.json.indicadores){
    pais = i.json.indicadores;

  } else if (i.json.contexto_pais?.error){
    error.push(i.json.contexto_pais.error);
    pais= {estado: "incompleto"};
  }

  //RAMA 3
  if(i.json.bibliografia){
    libro = i.json.bibliografia;

  } else if(i.json.recursos_academicos?.error){
    error.push(i.json.recursos_academicos?.error);
    libro={estado:"incompleto"};
  }

});

// Obtener tiempo actual 
const tiempo_Actual = new Date().toISOString();

// Salida json
const reporte_estructura = {
  reporte: {
    version: "1.0",
    timestamp: tiempo_Actual,
    estado: error.length > 0 ? "incompleto":"completo",
    fuentes: ["open-meteo","rest-countries","open-library"],
    clima_regional: clima,
    contexto_pais: pais,
    recursos_academicos: libro
  }
};

//En caso de error
if(error.length > 0){
  reporte_estructura.reporte.detalles_error = error;
}

return [{ json: reporte_estructura}];
